import json

# Check available variables more carefully
vars_dict = {}
for key in list(locals().keys()):
    if 'query_db' in key:
        value = locals()[key]
        vars_dict[key] = {
            'type': str(type(value)),
            'is_str': isinstance(value, str),
            'is_list': isinstance(value, list)
        }
        if isinstance(value, list):
            vars_dict[key]['length'] = len(value)
        if isinstance(value, str):
            vars_dict[key]['value'] = value

print('__RESULT__:')
print(json.dumps(vars_dict))

